168		using AstSrcLocType = Location;
169	
170		// convert an node type to a string (e.g. for debug output)
171		std::string type2str(AstNodeType type);
172	
173		// The AST is built using instances of this struct
174		struct AstNode
175		{
176			// for dict<> and pool<>
177			unsigned int hashidx_;
178			[[nodiscard]] Hasher hash_into(Hasher h) const { h.eat(hashidx_); return h; }
179	
180			// this nodes type
181			AstNodeType type;
182	
183			// the list of child nodes for this node
184			std::vector<std::unique_ptr<AstNode>> children;
185	
186			// the list of attributes assigned to this node
187			std::map<RTLIL::IdString, std::unique_ptr<AstNode>> attributes;
188			bool get_bool_attribute(RTLIL::IdString id);
189	
190			// node content - most of it is unused in most node types
191			std::string str;
192			std::vector<RTLIL::State> bits;
193			bool is_input, is_output, is_reg, is_logic, is_signed, is_string, is_wand, is_wor, range_valid, range_swapped, was_checked, is_unsized, is_custom_type;
194			int port_id, range_left, range_right;
195			uint32_t integer;
196			double realvalue;
197			// set for IDs typed to an enumeration, not used
198			bool is_enum;
199	
200			// Declared range for array dimension.
201			struct dimension_t {
202				int range_right;     // lsb in [msb:lsb]
203				int range_width;     // msb - lsb + 1
204				bool range_swapped;  // if the declared msb < lsb, msb and lsb above are swapped
205			};
206			// Packed and unpacked dimensions for arrays.
207			// Unpacked dimensions go first, to follow the order of indexing.
208			std::vector<dimension_t> dimensions;
209			// Number of unpacked dimensions.
210			int unpacked_dimensions;
211	
212			// this is set by simplify and used during RTLIL generation
213			AstNode* id2ast;
214	
215			// this is used by simplify to detect if basic analysis has been performed already on the node
216			bool basic_prep;
217	
218			// this is used for ID references in RHS expressions that should use the "new" value for non-blocking assignments
219			bool lookahead;
220	
221			// this is the original sourcecode location that resulted in this AST node
222			// it is automatically set by the constructor using AST::current_filename and
223			// the AST::get_line_num() callback function.
224			AstSrcLocType location;
225	
226			// are we embedded in an lvalue, param?
227			// (see fixup_hierarchy_flags)
228			bool in_lvalue;
229			bool in_param;
230			bool in_lvalue_from_above;
231			bool in_param_from_above;
232	
233			// creating and deleting nodes
234			AstNode(AstSrcLocType loc, AstNodeType type = AST_NONE, std::unique_ptr<AstNode> child1 = nullptr, std::unique_ptr<AstNode> child2 = nullptr, std::unique_ptr<AstNode> child3 = nullptr, std::unique_ptr<AstNode> child4 = nullptr);
235			std::unique_ptr<AstNode> clone() const;
236			void cloneInto(AstNode &other) const;
237			void delete_children();
238			~AstNode();
239	
240			enum mem2reg_flags
241			{
242				/* status flags */
243				MEM2REG_FL_ALL       = 0x00000001,
244				MEM2REG_FL_ASYNC     = 0x00000002,
245				MEM2REG_FL_INIT      = 0x00000004,
246	
247				/* candidate flags */
248				MEM2REG_FL_FORCED    = 0x00000100,
249				MEM2REG_FL_SET_INIT  = 0x00000200,
250				MEM2REG_FL_SET_ELSE  = 0x00000400,
251				MEM2REG_FL_SET_ASYNC = 0x00000800,
252				MEM2REG_FL_EQ2       = 0x00001000,
253				MEM2REG_FL_CMPLX_LHS = 0x00002000,
254				MEM2REG_FL_CONST_LHS = 0x00004000,
255				MEM2REG_FL_VAR_LHS   = 0x00008000,
256	
257				/* proc flags */
258				MEM2REG_FL_EQ1       = 0x01000000,
259			};
260	
261			// simplify() creates a simpler AST by unrolling for-loops, expanding generate blocks, etc.
262			// it also sets the id2ast pointers so that identifier lookups are fast in genRTLIL()
263			bool simplify(bool const_fold, int stage, int width_hint, bool sign_hint);
264			void replace_result_wire_name_in_function(const std::string &from, const std::string &to);
265			std::unique_ptr<AstNode> readmem(bool is_readmemh, std::string mem_filename, AstNode *memory, int start_addr, int finish_addr, bool unconditional_init);
266			void expand_genblock(const std::string &prefix);
267			void label_genblks(std::set<std::string>& existing, int &counter);
268			void mem2reg_as_needed_pass1(dict<AstNode*, pool<std::string>> &mem2reg_places,
269					dict<AstNode*, uint32_t> &mem2reg_flags, dict<AstNode*, uint32_t> &proc_flags, uint32_t &status_flags);
270			bool mem2reg_as_needed_pass2(pool<AstNode*> &mem2reg_set, AstNode *mod, AstNode *block, AstNode* async_block);
271			bool mem2reg_check(pool<AstNode*> &mem2reg_set);
272			void mem2reg_remove(pool<AstNode*> &mem2reg_set);
273			void meminfo(int &mem_width, int &mem_size, int &addr_bits);
274			bool detect_latch(const std::string &var);
275			const RTLIL::Module* lookup_cell_module();
276	
277			// additional functionality for evaluating constant functions
278			struct varinfo_t {
279				RTLIL::Const val;
280				int offset;
281				bool range_swapped;
282				bool is_signed;
283				AstNode *arg = nullptr;
284				bool explicitly_sized;
285			};
286			bool has_const_only_constructs();
287			bool replace_variables(std::map<std::string, varinfo_t> &variables, AstNode *fcall, bool must_succeed);
288			std::unique_ptr<AstNode> eval_const_function(AstNode *fcall, bool must_succeed);
289			bool is_simple_const_expr();
290	
291			// helper for parsing format strings
292			Fmt processFormat(int stage, bool sformat_like, int default_base = 10, size_t first_arg_at = 0, bool may_fail = false);
293	
294			bool is_recursive_function() const;
295			std::pair<AstNode*, AstNode*> get_tern_choice();
296	
297			// create a human-readable text representation of the AST (for debugging)
298			void dumpAst(FILE *f, std::string indent) const;
299			void dumpVlog(FILE *f, std::string indent) const;
300	
301			// Generate RTLIL for a bind construct
302			std::vector<RTLIL::Binding *> genBindings() const;
303	
304			// used by genRTLIL() for detecting expression width and sign
305			void detectSignWidthWorker(int &width_hint, bool &sign_hint, bool *found_real = nullptr);
306			void detectSignWidth(int &width_hint, bool &sign_hint, bool *found_real = nullptr);
307	
308			// create RTLIL code for this AST node
309			// for expressions the resulting signal vector is returned
310			// all generated cell instances, etc. are written to the RTLIL::Module pointed to by AST_INTERNAL::current_module
311			RTLIL::SigSpec genRTLIL(int width_hint = -1, bool sign_hint = false);
312			RTLIL::SigSpec genWidthRTLIL(int width, bool sgn, const dict<RTLIL::SigBit, RTLIL::SigBit> *new_subst_ptr = nullptr);
313	
314			// compare AST nodes
315			bool operator==(const AstNode &other) const;
316			bool operator!=(const AstNode &other) const;
317			bool contains(const AstNode *other) const;
318			AstNode operator=(AstNode) = delete;
319	
320			// helper functions for creating AST nodes for constants
321			static std::unique_ptr<AstNode> mkconst_int(AstSrcLocType loc, uint32_t v, bool is_signed, int width = 32);
322			static std::unique_ptr<AstNode> mkconst_bits(AstSrcLocType loc, const std::vector<RTLIL::State> &v, bool is_signed, bool is_unsized);
323			static std::unique_ptr<AstNode> mkconst_bits(AstSrcLocType loc, const std::vector<RTLIL::State> &v, bool is_signed);
324			static std::unique_ptr<AstNode> mkconst_str(AstSrcLocType loc, const std::vector<RTLIL::State> &v);
325			static std::unique_ptr<AstNode> mkconst_str(AstSrcLocType loc, const std::string &str);
326	
327			// helper function to create an AST node for a temporary register
328			std::unique_ptr<AstNode> mktemp_logic(AstSrcLocType loc, const std::string &name, AstNode *mod, bool nosync, int range_left, int range_right, bool is_signed);
329	
330			// helper function for creating sign-extended const objects
331			RTLIL::Const bitsAsConst(int width, bool is_signed);
332			RTLIL::Const bitsAsConst(int width = -1);
333			RTLIL::Const bitsAsUnsizedConst(int width);
334			RTLIL::Const asAttrConst() const;
335			RTLIL::Const asParaConst() const;
336			uint64_t asInt(bool is_signed);
337			bool bits_only_01() const;
338			bool asBool() const;
339	
340			// helper functions for real valued const eval
341			int isConst() const; // return '1' for AST_CONSTANT and '2' for AST_REALVALUE
342			double asReal(bool is_signed);
343			RTLIL::Const realAsConst(int width);
344	
345			// helpers for enum
346			void allocateDefaultEnumValues();
347			void annotateTypedEnums(AstNode *template_node);
348	
349			// helpers for locations
350			std::string loc_string() const;
351	
352			// Helper for looking up identifiers which are prefixed with the current module name
353			std::string try_pop_module_prefix() const;
354	
355			// helper to clone the node with some of its subexpressions replaced with zero (this is used
356			// to evaluate widths of dynamic ranges)
357			std::unique_ptr<AstNode> clone_at_zero();
358	
359			void set_attribute(RTLIL::IdString key, std::unique_ptr<AstNode> node)
360			{
361				node->set_in_param_flag(true);
362				attributes[key] = std::move(node);
363			}
364	
365			// helper to set in_lvalue/in_param flags from the hierarchy context (the actual flag
366			// can be overridden based on the intrinsic properties of this node, i.e. based on its type)
367			void set_in_lvalue_flag(bool flag, bool no_descend = false);
368			void set_in_param_flag(bool flag, bool no_descend = false);
369	
370			// fix up the hierarchy flags (in_lvalue/in_param) of this node and its children
371			//
372			// to keep the flags in sync, fixup_hierarchy_flags(true) needs to be called once after
373			// parsing the AST to walk the full tree, then plain fixup_hierarchy_flags() performs
374			// localized fixups after modifying children/attributes of a particular node
375			void fixup_hierarchy_flags(bool force_descend = false);
376	
377			// helpers for indexing
378			std::unique_ptr<AstNode> make_index_range(AstNode *node, bool unpacked_range = false);
379			AstNode *get_struct_member() const;
380	
381			// helper to print errors from simplify/genrtlil code
382			[[noreturn]] void formatted_input_error(std::string str) const;
383			template <typename... Args>
384			[[noreturn]] void input_error(FmtString<TypeIdentity<Args>...> fmt, const Args &... args) const
385			{
386				formatted_input_error(fmt.format(args...));
387			}
388		};
389	
390		// process an AST tree (ast must point to an AST_DESIGN node) and generate RTLIL code
391		void process(RTLIL::Design *design, AstNode *ast, bool nodisplay, bool dump_ast1, bool dump_ast2, bool no_dump_ptr, bool dump_vlog1, bool dump_vlog2, bool dump_rtlil, bool nolatches, bool nomeminit,
392				bool nomem2reg, bool mem2reg, bool noblackbox, bool lib, bool nowb, bool noopt, bool icells, bool pwires, bool nooverwrite, bool overwrite, bool defer, bool autowire);
393	
394		// parametric modules are supported directly by the AST library
395		// therefore we need our own derivate of RTLIL::Module with overloaded virtual functions
396		struct AstModule : RTLIL::Module {
397			std::unique_ptr<AstNode> ast;
398			bool nolatches, nomeminit, nomem2reg, mem2reg, noblackbox, lib, nowb, noopt, icells, pwires, autowire;
399			RTLIL::IdString derive(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Const> &parameters, bool mayfail) override;
400			RTLIL::IdString derive(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Const> &parameters, const dict<RTLIL::IdString, RTLIL::Module*> &interfaces, const dict<RTLIL::IdString, RTLIL::IdString> &modports, bool mayfail) override;
401			std::string derive_common(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Const> &parameters, std::unique_ptr<AstNode>* new_ast_out, bool quiet = false);
402			void expand_interfaces(RTLIL::Design *design, const dict<RTLIL::IdString, RTLIL::Module *> &local_interfaces) override;
403			bool reprocess_if_necessary(RTLIL::Design *design) override;
404			RTLIL::Module *clone() const override;
405			void loadconfig() const;
406		};
407	
408		// this must be set by the language frontend before parsing the sources
409		// the AstNode constructor then uses current_filename and get_line_num()
410		// to initialize the filename and linenum properties of new nodes
411		// extern std::string current_filename;
412		// also set by the language frontend to control some AST processing
413		extern bool sv_mode_but_global_and_used_for_literally_one_condition;
414	
415		// for stats
416		unsigned long long astnode_count();
417	
418		// set set_line_num and get_line_num to internal dummy functions (done by simplify() and AstModule::derive
419		// to control the filename and linenum properties of new nodes not generated by a frontend parser)
420		void use_internal_line_num();
421	
422		// call a DPI function
423		std::unique_ptr<AstNode> dpi_call(AstSrcLocType loc, const std::string &rtype, const std::string &fname, const std::vector<std::string> &argtypes, const std::vector<std::unique_ptr<AstNode>> &args);
424	
425		// Helper functions related to handling SystemVerilog interfaces
426		std::pair<std::string,std::string> split_modport_from_type(std::string name_type);
427		AstNode * find_modport(AstNode *intf, std::string name);
428		void explode_interface_port(AstNode *module_ast, RTLIL::Module * intfmodule, std::string intfname, AstNode *modport);
429	
430		// Helper for setting the src attribute.
431		void set_src_attr(RTLIL::AttrObject *obj, const AstNode *ast);
432	
433		// generate standard $paramod... derived module name; parameters should be
434		// in the order they are declared in the instantiated module
435		std::string derived_module_name(std::string stripped_name, const std::vector<std::pair<RTLIL::IdString, RTLIL::Const>> &parameters);
436	
437		// used to provide simplify() access to the current design for looking up
438		// modules, ports, wires, etc.
439		void set_simplify_design_context(const RTLIL::Design *design);
440	}
441	
442	namespace AST_INTERNAL
443	{
444		// internal state variables
445		extern bool flag_nodisplay, flag_dump_ast1, flag_dump_ast2, flag_no_dump_ptr, flag_dump_rtlil, flag_nolatches, flag_nomeminit;
446		extern bool flag_nomem2reg, flag_mem2reg, flag_lib, flag_noopt, flag_icells, flag_pwires, flag_autowire;
447		extern AST::AstNode *current_ast, *current_ast_mod;
448		extern std::map<std::string, AST::AstNode*> current_scope;
449		extern const dict<RTLIL::SigBit, RTLIL::SigBit> *genRTLIL_subst_ptr;
450		extern RTLIL::SigSpec ignoreThisSignalsInInitial;
451		extern AST::AstNode *current_always, *current_top_block, *current_block, *current_block_child;
452		extern RTLIL::Module *current_module;
453		extern bool current_always_clocked;
454		extern dict<std::string, int> current_memwr_count;
455		extern dict<std::string, pool<int>> current_memwr_visible;
456		struct LookaheadRewriter;
457		struct ProcessGenerator;
458	
459		// Create and add a new AstModule from new_ast, then use it to replace
460		// old_module in design, renaming old_module to move it out of the way.
461		// Return the new module.
462		//
463		// If original_ast is not null, it will be used as the AST node for the
464		// new module. Otherwise, new_ast will be used.
465		RTLIL::Module *
466		process_and_replace_module(RTLIL::Design *design,
467		                           RTLIL::Module *old_module,
468		                           AST::AstNode *new_ast,
469		                           std::unique_ptr<AST::AstNode> original_ast = nullptr);
470	}
471	
472	YOSYS_NAMESPACE_END
473	
474	#endif
