45	// helper function for creating RTLIL code for unary operations
46	static RTLIL::SigSpec uniop2rtlil(AstNode *that, IdString type, int result_width, const RTLIL::SigSpec &arg, bool gen_attributes = true)
47	{
48		IdString name = stringf("%s$%s:%d$%d", type, RTLIL::encode_filename(*that->location.begin.filename), that->location.begin.line, autoidx++);
49		RTLIL::Cell *cell = current_module->addCell(name, type);
50		set_src_attr(cell, that);
51	
52		RTLIL::Wire *wire = current_module->addWire(cell->name.str() + "_Y", result_width);
53		set_src_attr(wire, that);
54		wire->is_signed = that->is_signed;
55	
56		if (gen_attributes)
57			for (auto &attr : that->attributes) {
58				if (attr.second->type != AST_CONSTANT)
59					that->input_error("Attribute `%s' with non-constant value!\n", attr.first);
60				cell->attributes[attr.first] = attr.second->asAttrConst();
61			}
62	
63		cell->parameters[ID::A_SIGNED] = RTLIL::Const(that->children[0]->is_signed);
64		cell->parameters[ID::A_WIDTH] = RTLIL::Const(arg.size());
65		cell->setPort(ID::A, arg);
66	
67		cell->parameters[ID::Y_WIDTH] = result_width;
68		cell->setPort(ID::Y, wire);
69		return wire;
70	}
