72	// helper function for extending bit width (preferred over SigSpec::extend() because of correct undef propagation in ConstEval)
73	static void widthExtend(AstNode *that, RTLIL::SigSpec &sig, int width, bool is_signed)
74	{
75		if (width <= sig.size()) {
76			sig.extend_u0(width, is_signed);
77			return;
78		}
79	
80		IdString name = stringf("$extend$%s:%d$%d", RTLIL::encode_filename(*that->location.begin.filename), that->location.begin.line, autoidx++);
81		RTLIL::Cell *cell = current_module->addCell(name, ID($pos));
82		set_src_attr(cell, that);
83	
84		RTLIL::Wire *wire = current_module->addWire(cell->name.str() + "_Y", width);
85		set_src_attr(wire, that);
86		wire->is_signed = that->is_signed;
87	
88		if (that != nullptr)
89			for (auto &attr : that->attributes) {
90				if (attr.second->type != AST_CONSTANT)
91					that->input_error("Attribute `%s' with non-constant value!\n", attr.first);
92				cell->attributes[attr.first] = attr.second->asAttrConst();
93			}
94	
95		cell->parameters[ID::A_SIGNED] = RTLIL::Const(is_signed);
96		cell->parameters[ID::A_WIDTH] = RTLIL::Const(sig.size());
97		cell->setPort(ID::A, sig);
98	
99		cell->parameters[ID::Y_WIDTH] = width;
100		cell->setPort(ID::Y, wire);
101		sig = wire;
102	}
