104	// helper function for creating RTLIL code for binary operations
105	static RTLIL::SigSpec binop2rtlil(AstNode *that, IdString type, int result_width, const RTLIL::SigSpec &left, const RTLIL::SigSpec &right)
106	{
107		IdString name = stringf("%s$%s:%d$%d", type, RTLIL::encode_filename(*that->location.begin.filename), that->location.begin.line, autoidx++);
108		RTLIL::Cell *cell = current_module->addCell(name, type);
109		set_src_attr(cell, that);
110	
111		RTLIL::Wire *wire = current_module->addWire(cell->name.str() + "_Y", result_width);
112		set_src_attr(wire, that);
113		wire->is_signed = that->is_signed;
114	
115		for (auto &attr : that->attributes) {
116			if (attr.second->type != AST_CONSTANT)
117				that->input_error("Attribute `%s' with non-constant value!\n", attr.first);
118			cell->attributes[attr.first] = attr.second->asAttrConst();
119		}
120	
121		cell->parameters[ID::A_SIGNED] = RTLIL::Const(that->children[0]->is_signed);
122		cell->parameters[ID::B_SIGNED] = RTLIL::Const(that->children[1]->is_signed);
123	
124		cell->parameters[ID::A_WIDTH] = RTLIL::Const(left.size());
125		cell->parameters[ID::B_WIDTH] = RTLIL::Const(right.size());
126	
127		cell->setPort(ID::A, left);
128		cell->setPort(ID::B, right);
129	
130		cell->parameters[ID::Y_WIDTH] = result_width;
131		cell->setPort(ID::Y, wire);
132		return wire;
133	}
