135	// helper function for creating RTLIL code for multiplexers
136	static RTLIL::SigSpec mux2rtlil(AstNode *that, const RTLIL::SigSpec &cond, const RTLIL::SigSpec &left, const RTLIL::SigSpec &right)
137	{
138		log_assert(cond.size() == 1);
139	
140		std::stringstream sstr;
141		sstr << "$ternary$" << RTLIL::encode_filename(*that->location.begin.filename) << ":" << that->location.begin.line << "$" << (autoidx++);
142	
143		RTLIL::Cell *cell = current_module->addCell(sstr.str(), ID($mux));
144		set_src_attr(cell, that);
145	
146		RTLIL::Wire *wire = current_module->addWire(cell->name.str() + "_Y", left.size());
147		set_src_attr(wire, that);
148		wire->is_signed = that->is_signed;
149	
150		for (auto &attr : that->attributes) {
151			if (attr.second->type != AST_CONSTANT)
152				that->input_error("Attribute `%s' with non-constant value!\n", attr.first);
153			cell->attributes[attr.first] = attr.second->asAttrConst();
154		}
155	
156		cell->parameters[ID::WIDTH] = RTLIL::Const(left.size());
157	
158		cell->setPort(ID::A, right);
159		cell->setPort(ID::B, left);
160		cell->setPort(ID::S, cond);
161		cell->setPort(ID::Y, wire);
162	
163		return wire;
164	}
