166	static void check_unique_id(RTLIL::Module *module, RTLIL::IdString id,
167			const AstNode *node, const char *to_add_kind)
168	{
169		auto already_exists = [&](const RTLIL::AttrObject *existing, const char *existing_kind) {
170			std::string src = existing->get_string_attribute(ID::src);
171			std::string location_str = "earlier";
172			if (!src.empty())
173				location_str = "at " + src;
174			node->input_error("Cannot add %s `%s' because a %s with the same name was already created %s!\n",
175							  to_add_kind, id.c_str(), existing_kind, location_str.c_str());
176		};
177	
178		if (const RTLIL::Wire *wire = module->wire(id))
179			already_exists(wire, "signal");
